import math
import rclpy
from rclpy.node import Node
from geometry_msgs.msg import Twist, TransformStamped, PoseStamped
from nav_msgs.msg import Odometry, Path
from sensor_msgs.msg import JointState
from std_msgs.msg import Float32
from tf2_ros import TransformBroadcaster

class OdomNode(Node):
    def __init__(self):
        super().__init__('odom_node')

        # ── Suscriptores ──────────────────────────────────────────────────────
        # RPM reales desde encoders (ESP32)
        self.left_rpm_sub  = self.create_subscription(Float32, '/real_rpm_left',  self.left_rpm_callback,  10)
        self.right_rpm_sub = self.create_subscription(Float32, '/real_rpm_right', self.right_rpm_callback, 10)

        # Yaw del IMU en GRADOS desde ESP32 (integración gyro ya hecha en la ESP32)
        self.imu_yaw_sub   = self.create_subscription(Float32, '/imu_yaw', self.imu_yaw_callback, 10)

        # ── Publicadores ──────────────────────────────────────────────────────
        self.odom_pub  = self.create_publisher(Odometry,    '/odom',        10)
        self.joint_pub = self.create_publisher(JointState,  '/joint_states', 10)
        self.path_pub  = self.create_publisher(Path,        '/path',         10)

        # TF broadcaster (odom → base_link)
        self.tf_broadcaster = TransformBroadcaster(self)

        # ── Estado del robot ──────────────────────────────────────────────────
        self.x   = 0.0   # posición X en el frame odom (metros)
        self.y   = 0.0   # posición Y en el frame odom (metros)
        self.th  = 0.0   # orientación (radianes) — viene del IMU

        # Velocidades lineales/angulares calculadas
        self.vx  = 0.0
        self.vth = 0.0

        # RPM de los encoders
        self.rpm_left  = 0.0
        self.rpm_right = 0.0

        # Timeout: si no llegan datos de RPM en X segundos → robot detenido
        self.RPM_TIMEOUT_SEC = 0.3      # 300 ms sin datos = robot parado
        self.RPM_DEADBAND    = 1.0      # RPM menores a esto se tratan como 0
        self.last_left_rpm_time  = None  # tiempo del último mensaje izquierdo
        self.last_right_rpm_time = None  # tiempo del último mensaje derecho

        # Yaw del IMU (grados → lo convertimos a radianes al usarlo)
        self.imu_yaw_deg = 0.0
        self.imu_yaw_received = False   # bandera: esperamos al menos un dato

        # Posición angular acumulada de las llantas (para JointStates → giran en RViz)
        self.left_wheel_pos  = 0.0
        self.right_wheel_pos = 0.0

        # ── Parámetros del robot ──────────────────────────────────────────────
        # ⚠️ Ajusta estos valores a tu robot físico
        self.wheel_radius = 0.033   # radio de la llanta en metros  (3.3 cm)
        self.wheel_base   = 0.16    # separación entre llantas en metros (16 cm)

        # ── Path acumulado ────────────────────────────────────────────────────
        self.path_msg = Path()
        self.path_msg.header.frame_id = 'odom'

        # Tiempo
        self.last_time = self.get_clock().now()

        # Timer a 30 Hz para calcular y publicar
        self.timer = self.create_timer(1.0 / 30.0, self.update_odometry)

        self.get_logger().info('✅ Odom Node (Encoders + IMU Yaw) Iniciado')
        self.get_logger().info('   Esperando tópicos: /real_rpm_left, /real_rpm_right, /imu_yaw')

    # ── Callbacks de suscripciones ────────────────────────────────────────────

    def left_rpm_callback(self, msg: Float32):
        self.rpm_left = msg.data
        self.last_left_rpm_time = self.get_clock().now()

    def right_rpm_callback(self, msg: Float32):
        self.rpm_right = msg.data
        self.last_right_rpm_time = self.get_clock().now()

    def imu_yaw_callback(self, msg: Float32):
        """Recibe el yaw en grados desde la ESP32 y lo convierte a radianes."""
        self.imu_yaw_deg = msg.data
        self.imu_yaw_received = True
        # Convertir a radianes para usar en cálculos internos
        self.th = math.radians(self.imu_yaw_deg)

    # ── Cálculo principal a 30 Hz ─────────────────────────────────────────────

    def update_odometry(self):
        current_time = self.get_clock().now()
        dt = (current_time - self.last_time).nanoseconds / 1e9

        if dt <= 0.0:
            self.last_time = current_time
            return

        # ── 1. Comprobar timeout de RPM ───────────────────────────────────────
        # Si no han llegado datos en RPM_TIMEOUT_SEC → robot detenido
        now = self.get_clock().now()
        rpm_left_active  = (
            self.last_left_rpm_time  is not None and
            (now - self.last_left_rpm_time).nanoseconds / 1e9 < self.RPM_TIMEOUT_SEC
        )
        rpm_right_active = (
            self.last_right_rpm_time is not None and
            (now - self.last_right_rpm_time).nanoseconds / 1e9 < self.RPM_TIMEOUT_SEC
        )

        # Aplicar deadband y timeout
        rpm_left_eff  = self.rpm_left  if (rpm_left_active  and abs(self.rpm_left)  >= self.RPM_DEADBAND) else 0.0
        rpm_right_eff = self.rpm_right if (rpm_right_active and abs(self.rpm_right) >= self.RPM_DEADBAND) else 0.0

        # ── 2. Cinemática diferencial desde encoders ──────────────────────────
        # Velocidad lineal de cada rueda (m/s)  V = RPM * 2π * R / 60
        v_left  = (rpm_left_eff  * 2.0 * math.pi * self.wheel_radius) / 60.0
        v_right = (rpm_right_eff * 2.0 * math.pi * self.wheel_radius) / 60.0

        # Velocidad lineal del robot (m/s) y angular (rad/s)
        self.vx  = (v_right + v_left) / 2.0
        self.vth = (v_right - v_left) / self.wheel_base

        # ── 2. Integrar posición (X,Y) usando el yaw del IMU ─────────────────
        # Si el IMU aún no ha enviado datos usamos th integrado desde RPM
        if not self.imu_yaw_received:
            self.th += self.vth * dt

        delta_x = self.vx * math.cos(self.th) * dt
        delta_y = self.vx * math.sin(self.th) * dt

        self.x += delta_x
        self.y += delta_y

        # ── 3. Posición angular de ruedas (para JointStates) ─────────────────
        w_right = rpm_right_eff * 2.0 * math.pi / 60.0
        w_left  = rpm_left_eff  * 2.0 * math.pi / 60.0
        self.right_wheel_pos += w_right * dt
        self.left_wheel_pos  += w_left  * dt

        # ── 4. Quaternión desde el ángulo th ──────────────────────────────────
        q_z = math.sin(self.th / 2.0)
        q_w = math.cos(self.th / 2.0)

        # ── 5. Publicar TF odom → base_link ──────────────────────────────────
        t = TransformStamped()
        t.header.stamp    = current_time.to_msg()
        t.header.frame_id = 'odom'
        t.child_frame_id  = 'base_link'
        t.transform.translation.x = self.x
        t.transform.translation.y = self.y
        t.transform.translation.z = 0.0
        t.transform.rotation.x = 0.0
        t.transform.rotation.y = 0.0
        t.transform.rotation.z = q_z
        t.transform.rotation.w = q_w
        self.tf_broadcaster.sendTransform(t)

        # ── 6. Publicar Odometry ──────────────────────────────────────────────
        odom = Odometry()
        odom.header.stamp      = current_time.to_msg()
        odom.header.frame_id   = 'odom'
        odom.child_frame_id    = 'base_link'
        odom.pose.pose.position.x    = self.x
        odom.pose.pose.position.y    = self.y
        odom.pose.pose.position.z    = 0.0
        odom.pose.pose.orientation.x = 0.0
        odom.pose.pose.orientation.y = 0.0
        odom.pose.pose.orientation.z = q_z
        odom.pose.pose.orientation.w = q_w
        odom.twist.twist.linear.x    = self.vx
        odom.twist.twist.angular.z   = self.vth
        self.odom_pub.publish(odom)

        # ── 7. Publicar JointStates (llantas giran en RViz) ──────────────────
        joint_state = JointState()
        joint_state.header.stamp = current_time.to_msg()
        joint_state.name     = ['A', 'B']   # nombres de joints en tu URDF
        joint_state.position = [self.left_wheel_pos, self.right_wheel_pos]
        self.joint_pub.publish(joint_state)

        # ── 8. Acumular y publicar trayectoria (Path) ─────────────────────────
        pose_stamped = PoseStamped()
        pose_stamped.header.stamp      = current_time.to_msg()
        pose_stamped.header.frame_id   = 'odom'
        pose_stamped.pose.position.x   = self.x
        pose_stamped.pose.position.y   = self.y
        pose_stamped.pose.position.z   = 0.0
        pose_stamped.pose.orientation.z = q_z
        pose_stamped.pose.orientation.w = q_w

        self.path_msg.header.stamp = current_time.to_msg()
        self.path_msg.poses.append(pose_stamped)

        # Limitar el historial del path a 5000 puntos para no saturar memoria
        if len(self.path_msg.poses) > 5000:
            self.path_msg.poses = self.path_msg.poses[-5000:]

        self.path_pub.publish(self.path_msg)

        self.last_time = current_time


def main(args=None):
    rclpy.init(args=args)
    node = OdomNode()
    rclpy.spin(node)
    node.destroy_node()
    rclpy.shutdown()


if __name__ == '__main__':
    main()
